const item = $input.item.json;
const now = Date.now();

const isWebhook = !!item.body || !!item.headers;
const isEmail   = !!item.from;

let submissionData = {};
if (isWebhook) {
  const body = item.body || item;
  submissionData = {
    tenant_id:    body.tenant_id    || 'default',
    job_id:       body.job_id       || 'JOB_001',
    source:       body.source       || 'web_form',
    sender_email: body.applicant_email || 'unknown@email.com',
    sender_name:  body.applicant_name  || 'Unknown',
    email_subject: body.subject || 'CV Application',
    intake_type:  'webhook'
  };
} else if (isEmail) {
  const fromText = item.from && typeof item.from === 'object' ? item.from.text : (item.from || 'unknown@email.com');
  submissionData = {
    tenant_id:    'default',
    job_id:       item.subject && item.subject.match(/JOB_[A-Z0-9]+/) ? item.subject.match(/JOB_[A-Z0-9]+/)[0] : 'JOB_001',
    source:       'email',
    sender_email: fromText,
    sender_name:  (item.from && item.from.value && item.from.value[0]) ? item.from.value[0].name : 'Applicant',
    email_subject: item.subject || 'CV Application',
    intake_type:  'email'
  };
}

// Rate limiting dedup key — same email + job within 5 min window
const rateKey = submissionData.sender_email.toLowerCase();
const submissionId = rateKey + '_' + submissionData.job_id + '_' + Math.floor(now/300000).toString();

// File validation
const attachments = item.attachments || [];
const allowedExts = ['.pdf', '.docx', '.doc', '.txt'];
let fileValid = false;
let fileName = 'no_file';
let fileSize = 0;
let fileMime = '';

if (attachments.length > 0) {
  const file = attachments[0];
  fileName = (file.fileName || file.filename || 'cv.pdf').toLowerCase();
  fileSize = file.length || file.size || 0;
  fileMime = file.contentType || file.mimeType || '';
  const ext = '.' + fileName.split('.').pop();
  fileValid = allowedExts.includes(ext) || fileMime.includes('pdf') || fileMime.includes('word') || fileMime.includes('text');
  if (fileSize > 5 * 1024 * 1024) {
    fileValid = false;
    submissionData.rejection_reason = 'File exceeds 5MB limit';
  }
} else {
  submissionData.rejection_reason = 'No attachment found';
}

// Prompt injection prevention — sanitize string fields
function sanitize(str) {
  if (!str) return '';
  return String(str)
    .replace(/ignore previous instructions/gi, '[BLOCKED]')
    .replace(/system prompt/gi, '[BLOCKED]')
    .replace(/you are now/gi, '[BLOCKED]')
    .replace(/<script[^>]*>.*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, '')
    .substring(0, 500);
}
submissionData.sender_name  = sanitize(submissionData.sender_name);
submissionData.sender_email = sanitize(submissionData.sender_email);

const validationPassed = fileValid && submissionData.sender_email.length > 3;

return [{
  json: {
    ...submissionData,
    submission_id:      submissionId,
    file_name:          fileName,
    file_size_kb:       Math.round(fileSize / 1024),
    file_mime:          fileMime,
    file_valid:         fileValid,
    validation_passed:  validationPassed,
    rejection_reason:   submissionData.rejection_reason || (validationPassed ? null : 'Validation failed'),
    received_at:        new Date().toISOString(),
    received_ts:        now,
    _raw_attachments:   JSON.stringify(attachments.map(a => ({ name: a.fileName || a.filename, size: a.length || a.size, type: a.contentType || a.mimeType })))
  }
}];

const item  = $input.item.json;
const config = $('🔄 Dedup Check & Merge Config').item.json;

let rawText = item.text || item.content || item.data || '';

if (!rawText || rawText.length < 20) {
  const binaryData = item.binary;
  if (binaryData) {
    const firstKey = Object.keys(binaryData)[0];
    if (binaryData[firstKey] && binaryData[firstKey].data) {
      try { rawText = Buffer.from(binaryData[firstKey].data, 'base64').toString('utf-8'); } catch(e) {}
    }
  }
}

const cleaned = rawText
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ')
  .replace(/\r\n/g, '\n').replace(/\r/g, '\n').replace(/\t/g, ' ')
  .replace(/ {3,}/g, '  ')
  .replace(/\n{4,}/g, '\n\n')
  .trim()
  .substring(0, 8000);

if (cleaned.length < 30) {
  throw new Error('CV text too short (' + cleaned.length + ' chars). File may be image-based PDF, password-protected, or corrupted.');
}

return [{
  json: {
    ...config,
    cv_text:       cleaned,
    cv_char_count: cleaned.length,
    cv_word_count: cleaned.split(/\s+/).filter(Boolean).length,
    extraction_ok: true
  }
}];

const aiRaw = $input.item.json.message && $input.item.json.message.content
  ? $input.item.json.message.content
  : ($input.item.json.content || $input.item.json.text || '');

const ctx = $('🧹 Clean & Validate CV Text').item.json;

// Parse AI JSON response
let cv;
try {
  const c = aiRaw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
  cv = JSON.parse(c);
} catch(e1) {
  try {
    const m = aiRaw.match(/\{[\s\S]*\}/);
    if (!m) throw new Error('No JSON object found');
    cv = JSON.parse(m[0]);
  } catch(e2) {
    cv = {
      name: ctx.sender_name, email: ctx.sender_email, phone: null, location: null,
      linkedin: null, years_experience: 0, current_role: 'Unknown', current_company: null,
      education_level: 'Unknown', education_institute: 'Unknown', graduation_year: null,
      skills_found: [], skills_missing: [], skills_additional: [], certifications: [],
      languages: [], employment_gaps: 'Parse failed', career_progression: 'Unknown',
      skills_score: 0, experience_score: 0, education_score: 0, communication_score: 0,
      leadership_score: 0, overall_ai_score: 0, decision: 'review', confidence: 'low',
      strengths: [], weaknesses: ['AI parsing failed — manual review required'],
      red_flags: ['Parse error: ' + e2.message], culture_fit_notes: '',
      summary: 'CV could not be parsed automatically. Manual review needed.',
      interview_questions: []
    };
  }
}

// Weighted scoring: Skills 35% | Experience 30% | Education 15% | Communication 10% | Leadership 10%
const W = { skills: 0.35, experience: 0.30, education: 0.15, communication: 0.10, leadership: 0.10 };
const S = {
  skills:        Math.min(100, Math.max(0, Number(cv.skills_score)        || 0)),
  experience:    Math.min(100, Math.max(0, Number(cv.experience_score)    || 0)),
  education:     Math.min(100, Math.max(0, Number(cv.education_score)     || 0)),
  communication: Math.min(100, Math.max(0, Number(cv.communication_score) || 0)),
  leadership:    Math.min(100, Math.max(0, Number(cv.leadership_score)    || 0))
};
const finalScore = Math.round(S.skills*W.skills + S.experience*W.experience + S.education*W.education + S.communication*W.communication + S.leadership*W.leadership);

const ST = ctx.shortlist_threshold || 70;
const RT = ctx.review_threshold    || 45;
const decision = finalScore >= ST ? 'shortlist' : finalScore >= RT ? 'review' : 'reject';

let priority;
if      (finalScore >= 90) priority = '🏆 EXCEPTIONAL';
else if (finalScore >= 80) priority = '🔥 HOT';
else if (finalScore >= 70) priority = '⭐ SHORTLISTED';
else if (finalScore >= 55) priority = '👀 REVIEW+';
else if (finalScore >= 45) priority = '🔵 REVIEW';
else                        priority = '❌ REJECTED';

// Bias flags for compliance
const biasFlags = [];
if (cv.graduation_year && cv.graduation_year < 1990) biasFlags.push('Age indicator detected — anonymize before interview');
if (cv.graduation_year && cv.graduation_year > 2024) biasFlags.push('Very recent graduate — ensure equal consideration');

// Unique candidate ID
const candidateId = 'CND_' + Date.now().toString(36).toUpperCase() + '_' + Math.random().toString(36).substr(2,4).toUpperCase();

const auditRecord = {
  candidateId, scoringVersion: '2.0', weights: W, rawScores: S,
  finalScore, decision, decisionReason: 'Score ' + finalScore + '/100. Thresholds: shortlist>=' + ST + ', review>=' + RT,
  biasFlags, aiConfidence: cv.confidence || 'unknown', scoredAt: new Date().toISOString()
};

const arr = (a) => Array.isArray(a) ? a.join(', ') : (a || '');

return [{
  json: {
    candidate_id:          candidateId,
    submission_id:         ctx.submission_id,
    dedup_key:             ctx.dedup_key,
    tenant_id:             ctx.tenant_id,
    job_id:                ctx.job_id,
    job_title:             ctx.job_title,
    company_name:          ctx.company_name,
    hiring_manager_email:  ctx.hiring_manager_email,
    slack_channel:         ctx.slack_channel,

    name:                  cv.name || ctx.sender_name,
    email:                 cv.email || ctx.sender_email,
    phone:                 cv.phone || 'Not provided',
    location:              cv.location || 'Not provided',
    linkedin:              cv.linkedin || '',
    current_role:          cv.current_role || 'Not specified',
    current_company:       cv.current_company || '',
    years_experience:      Number(cv.years_experience) || 0,
    education_level:       cv.education_level || 'Unknown',
    education_institute:   cv.education_institute || 'Unknown',
    graduation_year:       cv.graduation_year || '',
    career_progression:    cv.career_progression || 'Unknown',
    employment_gaps:       cv.employment_gaps || 'None detected',

    skills_found:          arr(cv.skills_found),
    skills_missing:        arr(cv.skills_missing),
    skills_additional:     arr(cv.skills_additional),
    certifications:        arr(cv.certifications),
    languages:             arr(cv.languages),

    skills_score:          S.skills,
    experience_score:      S.experience,
    education_score:       S.education,
    communication_score:   S.communication,
    leadership_score:      S.leadership,
    final_score:           finalScore,
    ai_confidence:         cv.confidence || 'unknown',

    decision:              decision,
    priority:              priority,

    strengths:             arr(cv.strengths),
    weaknesses:            arr(cv.weaknesses),
    red_flags:             arr(cv.red_flags) || 'None',
    culture_fit_notes:     cv.culture_fit_notes || '',
    summary:               cv.summary || '',
    interview_questions:   arr(cv.interview_questions),
    bias_flags:            biasFlags.join(' | ') || 'None',

    file_name:             ctx.file_name,
    cv_source:             ctx.source,
    cv_word_count:         ctx.cv_word_count,
    processed_at:          new Date().toISOString(),
    processing_date:       new Date().toLocaleDateString('en-GB', { timeZone: 'Asia/Karachi' }),
    processing_time:       new Date().toLocaleTimeString('en-PK', { timeZone: 'Asia/Karachi' }),
    _audit:                JSON.stringify(auditRecord)
  }
}];

const error = $input.item.json;
return [{
  json: {
    timestamp:      new Date().toISOString(),
    error_type:     error.name || 'UnknownError',
    error_message:  error.message || 'Unknown error',
    workflow_name:  'AI Resume Screening COMMERCIAL v2',
    node_name:      error.node && error.node.name ? error.node.name : 'unknown',
    execution_id:   error.execution && error.execution.id ? error.execution.id : 'unknown',
    error_data:     JSON.stringify(error).substring(0, 2000),
    severity:       (error.message || '').includes('OpenAI') ? 'HIGH' : 'MEDIUM'
  }
}];
